const items = $input.all();
const data = items[0].json;

const automations = data.body?.automations || data.automations || [];
const opportunity = data.body?.opportunity || data.opportunity || {};
const stageName = data.body?.stage_name || data.stage_name || '';
const pipelineName = data.body?.pipeline_name || data.pipeline_name || '';

const emails = [];

for (const rule of automations) {
  let toEmail = '';
  if (rule.email_to_type === 'custom') {
    toEmail = rule.email_to || '';
  } else {
    toEmail = opportunity.email || '';
  }

  const subject = (rule.email_subject || '')
    .replace('{{candidate_name}}', opportunity.contact_name || '')
    .replace('{{stage_name}}', stageName)
    .replace('{{pipeline_name}}', pipelineName)
    .replace('{{opp_name}}', opportunity.opp_name || '');

  const body = (rule.email_body || '')
    .replace('{{candidate_name}}', opportunity.contact_name || '')
    .replace('{{candidate_email}}', opportunity.email || '')
    .replace('{{stage_name}}', stageName)
    .replace('{{pipeline_name}}', pipelineName)
    .replace('{{opp_name}}', opportunity.opp_name || '');

  if (toEmail) {
    emails.push({
      to: toEmail,
      cc: rule.email_cc || '',
      from: rule.smtp_from || '',
      subject: subject,
      body: body,
      // SMTP details directly pass karo
      smtp_host: rule.smtp_host || '',
      smtp_port: rule.smtp_port || 587,
      smtp_user: rule.smtp_user || '',
      smtp_password: rule.smtp_password || ''
    });
  }
}

return emails.map(e => ({ json: e }));
